const item = $input.first();

const debugInfo = {
  jsonKeys: Object.keys(item.json || {}),
  binaryKeys: Object.keys(item.binary || {}),
  bodyKeys: Object.keys(item.json?.body || {}),
  filesKeys: Object.keys(item.json?.files || {}),
};

const body = item.json.body || item.json || {};
const files = item.json.files || {};

const uploadedFile =
  item.binary?.file ||
  item.binary?.data ||
  item.binary?.image ||
  files.file?.[0] ||
  files.data?.[0] ||
  files.image?.[0];

if (!uploadedFile) {
  throw new Error('File not found. Debug: ' + JSON.stringify(debugInfo));
}

return [{
  json: {
    postType: body.postType || body.post_type || 'quote post',
    topic: body.topic || '',
    mainMessage: body.mainMessage || body.main_message || body.message || '',
    format: body.format || '1:1',
    headline: body.headline || body.mainMessage || body.message || '',
    secondaryText: body.secondaryText || body.secondary_text || ''
  },
  binary: {
    data: uploadedFile
  }
}];

